'use client'

import { useEffect, useState } from 'react'
import Header from '@/components/Header'
import Footer from '@/components/Footer'
import CoreValues from '@/components/CoreValues'
import styles from './about.module.css'

interface SiteInfo {
  churchName?: string
  mission?: string
  vision?: string
  history?: string
  location?: {
    city: string
    address: string
  }
}

export default function AboutPage() {
  const [siteInfo, setSiteInfo] = useState<SiteInfo | null>(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    const fetchSiteInfo = async () => {
      try {
        const apiUrl = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001'
        const response = await fetch(`${apiUrl}/api/public/site`)
        const data = await response.json()
        
        if (data.success && data.data) {
          setSiteInfo(data.data)
        } else {
          // Fallback data
          setSiteInfo({
            churchName: 'VOSH Church International Kitengela',
            mission: 'To manifest Christ and be a house of solutions for our community.',
            vision: 'Building a community of believers who walk in holiness, unity, and purpose.',
            history: 'VOSH Church International Kitengela is a vibrant community of believers committed to manifesting Christ in our daily lives. We are dedicated to prayer, stewardship, holiness, advocacy, and unity.',
            location: {
              city: 'Kitengela',
              address: 'Along Baraka Road / Treewa Road, Next to Balozi Junior Academy'
            }
          })
        }
      } catch (error) {
        console.error('Error fetching site info:', error)
        // Fallback data
        setSiteInfo({
          churchName: 'VOSH Church International Kitengela',
          mission: 'To manifest Christ and be a house of solutions for our community.',
          vision: 'Building a community of believers who walk in holiness, unity, and purpose.',
          history: 'VOSH Church International Kitengela is a vibrant community of believers committed to manifesting Christ in our daily lives. We are dedicated to prayer, stewardship, holiness, advocacy, and unity.',
          location: {
            city: 'Kitengela',
            address: 'Along Baraka Road / Treewa Road, Next to Balozi Junior Academy'
          }
        })
      } finally {
        setLoading(false)
      }
    }

    fetchSiteInfo()
  }, [])

  return (
    <main>
      <Header />
      <div className={styles.container}>
        <div className={styles.hero}>
          <h1 className={styles.title}>About Us</h1>
          <p className={styles.subtitle}>
            {siteInfo?.churchName || 'VOSH Church International Kitengela'}
          </p>
        </div>

        {loading ? (
          <div className={styles.loading}>Loading...</div>
        ) : (
          <>
            <section className={styles.section}>
              <h2 className={styles.sectionTitle}>Our Mission</h2>
              <p className={styles.text}>
                {siteInfo?.mission || 'To manifest Christ and be a house of solutions for our community.'}
              </p>
            </section>

            <section className={styles.section}>
              <h2 className={styles.sectionTitle}>Our Vision</h2>
              <p className={styles.text}>
                {siteInfo?.vision || 'Building a community of believers who walk in holiness, unity, and purpose.'}
              </p>
            </section>

            <section className={styles.section}>
              <h2 className={styles.sectionTitle}>Our Story</h2>
              <p className={styles.text}>
                {siteInfo?.history || 'VOSH Church International Kitengela is a vibrant community of believers committed to manifesting Christ in our daily lives. We are dedicated to prayer, stewardship, holiness, advocacy, and unity.'}
              </p>
            </section>

            <section className={styles.section}>
              <h2 className={styles.sectionTitle}>Location</h2>
              <p className={styles.text}>
                <strong>City:</strong> {siteInfo?.location?.city || 'Kitengela'}
              </p>
              <p className={styles.text}>
                <strong>Address:</strong> {siteInfo?.location?.address || 'Along Baraka Road / Treewa Road, Next to Balozi Junior Academy'}
              </p>
            </section>

            <CoreValues />
          </>
        )}
      </div>
      <Footer />
    </main>
  )
}
